/**
 * Message
 */	
public class Message extends Entity implements Serializable {

	 int numAbOtpr;

	 int numAbPol;

	 int numKat;

	 double timeOtpr;

	 double dlina;

	 double timeObr;

	 double timePered;

    /**
     * Конструктор по умолчанию
     */
    public Message() {
    }

    /**
     * Конструктор, инициализирующий поля
     */
    public Message(int numAbOtpr, int numAbPol, int numKat, double timeOtpr, double dlina, double timeObr, double timePered) {
		this.numAbOtpr = numAbOtpr;
		this.numAbPol = numAbPol;
		this.numKat = numKat;
		this.timeOtpr = timeOtpr;
		this.dlina = dlina;
		this.timeObr = timeObr;
		this.timePered = timePered;
    }

	@Override
	public String toString() {
		return  
			"numAbOtpr = " + numAbOtpr +" " +
			"numAbPol = " + numAbPol +" " +
			"numKat = " + numKat +" " +
			"timeOtpr = " + timeOtpr +" " +
			"dlina = " + dlina +" " +
			"timeObr = " + timeObr +" " +
			"timePered = " + timePered +" ";
	}

	/**
	 * Это число используется при сохранении состояния модели<br>
	 * Его рекомендуется изменить в случае изменения класса
	 */ 
	private static final long serialVersionUID = 1L;

}
